sql:
SELECT family_name, speaker_percentage
FROM language_families 
WHERE speaker_percentage > 50;

SELECT role 
FROM project_researchers
WHERE project_id = 1;

external_knowledge:
- 'lighthouses' in the metaphor refer to 'projects', each one illuminating the path to its respective goal;
- 'ship' symbolizes the overarching research effort that aims to reach certain objectives or 'horizon';
- 'vigilant navigators' are the 'researchers' whose role is crucial in steering the research towards its goals, in this context, they have the role of 'lead';
- The metaphor reflects the critical roles these individuals play in leading research projects successfully.

sql:
SELECT variety_name, iso_code, glottolog_code
FROM language_varieties
WHERE family_id = 1;

external_knowledge:
- Main contributors: refers to the researchers who have made the most comments; 
- Top five most widely spoken language families: these are identified by the highest sum of speaker percentages among language families; 
- Most comments: the highest number of comments made by a single researcher for a specific language family.

- 'primary language group' refers to the family_id = 1;
- 'closely related' and 'distance below 80' refers to the condition where distance_value < 80;
- 'detailed codes' refer to the ISO codes and Glottolog codes of the language varieties.

sql:
SELECT DISTINCT lf.family_name
FROM language_families AS lf
INNER JOIN family_distances AS fd ON lf.family_id = fd.family_id;

SELECT project_id, data_value 
FROM project_data 
WHERE data_type = 'linguistic distance' AND data_value > 85.5575;

SELECT lv.variety_name, ld.distance_value
FROM language_varieties lv
JOIN linguistic_distances ld ON lv.variety_id = ld.variety_id;

SELECT family_name, MIN(speaker_percentage) AS faintest_echo
FROM language_families
WHERE speaker_percentage < 10;

SELECT p.project_name, pd.data_type
FROM projects p
JOIN project_data pd ON p.project_id = pd.project_id;
